// mm/src/components/paymentDelivery.js
import React, { useMemo, useState } from 'react';
import { createCheckoutSession } from '../api/checkout';

function isValidEmail(email) {
  const v = String(email || '').trim();
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v);
}

function getOriginSafe() {
  // Handles CRA + local dev + environments without window (tests)
  if (typeof window === 'undefined') return '';
  return window.location.origin || '';
}

export default function PaymentDelivery({
  packageId,
  packagePrices,
  email,
  onEmailChange,
  checkoutPayload, // function returning payload object
}) {
  const [isPaying, setIsPaying] = useState(false);
  const [error, setError] = useState('');

  const amount = useMemo(() => {
    const n = packagePrices?.[packageId];
    return Number.isFinite(n) ? n : 0;
  }, [packageId, packagePrices]);

  const canPay = useMemo(() => {
    return isValidEmail(email) && amount > 0 && !isPaying;
  }, [email, amount, isPaying]);

  const onPay = async () => {
    setError('');

    const cleanEmail = String(email || '').trim();

    if (!isValidEmail(cleanEmail)) {
      setError('Please enter a valid email address for delivery.');
      return;
    }

    if (!packageId) {
      setError('Please select a package to continue.');
      return;
    }

    if (!(amount > 0)) {
      setError('Invalid package amount. Please re-select your package.');
      return;
    }

    const origin = getOriginSafe();
    if (!origin) {
      setError('Unable to determine site origin. Please refresh and try again.');
      return;
    }

    setIsPaying(true);

    try {
      const payload = typeof checkoutPayload === 'function' ? checkoutPayload() : {};

      const resp = await createCheckoutSession({
        ...payload,
        packageId,
        amount,
        deliveryEmail: cleanEmail,
        successUrl: `${origin}/workflow/payment/success`,
        cancelUrl: `${origin}/workflow/order`,
      });

      const checkoutUrl = resp?.data?.checkoutUrl;
      const sessionId = resp?.data?.sessionId;

      if (checkoutUrl) {
        // Stripe Checkout redirect
        window.location.assign(checkoutUrl);
        return;
      }

      // If backend returns sessionId only, you'd redirect with Stripe.js.
      // Keeping this explicit so you don't silently "succeed" but do nothing.
      if (sessionId) {
        setError(
          'Checkout session was created but no checkoutUrl was returned. Update the backend to return { checkoutUrl }.'
        );
        return;
      }

      setError('Checkout failed: backend did not return checkoutUrl or sessionId.');
    } catch (e) {
      console.error(e);

      // more detailed error messaging when backend responds with details
      const status = e?.response?.status;
      const serverMsg =
        e?.response?.data?.message ||
        e?.response?.data?.error ||
        (typeof e?.response?.data === 'string' ? e.response.data : '');

      if (status) {
        setError(
          serverMsg
            ? `Payment failed (${status}): ${serverMsg}`
            : `Payment failed (${status}). Please try again.`
        );
      } else {
        setError('Payment failed. Please check your connection and try again.');
      }
    } finally {
      setIsPaying(false);
    }
  };

  return (
    <div className="border rounded-xl p-6 bg-white">
      <h2 className="text-2xl font-semibold text-slate-900 flex items-center gap-2">
        <span className="text-slate-600">💳</span> Payment &amp; Delivery
      </h2>

      <div className="mt-6">
        <label className="block text-sm font-medium text-slate-700">
          Email Address for File Delivery <span className="text-red-500">*</span>
        </label>

        <input
          value={email}
          onChange={(e) => onEmailChange && onEmailChange(e.target.value)}
          placeholder="your.email@example.com"
          className="mt-2 w-full border rounded-md px-3 py-2 outline-none focus:ring-2 focus:ring-blue-200"
          type="email"
          autoComplete="email"
        />

        <div className="mt-2 text-xs text-slate-500">
          Your formatted files will be delivered to this email address.
        </div>

        <div className="mt-4 rounded-lg bg-slate-50 border border-slate-200 p-4 text-sm text-slate-600">
          <span className="font-semibold">Secure Payment:</span> All transactions are processed securely through Stripe.
          Your payment information is encrypted and never stored on our servers.
        </div>

        {error ? <div className="mt-4 text-sm text-red-600">{error}</div> : null}

        <button
          type="button"
          onClick={onPay}
          disabled={!canPay}
          className={[
            'mt-6 w-full py-3 rounded-md text-white font-semibold flex items-center justify-center gap-2',
            canPay ? 'bg-blue-600 hover:bg-blue-700' : 'bg-slate-300 cursor-not-allowed',
          ].join(' ')}
        >
          {isPaying ? 'Redirecting…' : `Pay $${amount}`}
        </button>

        <div className="mt-3 text-xs text-slate-400">
          By continuing, you’ll be redirected to Stripe Checkout to complete payment.
        </div>
      </div>
    </div>
  );
}
